// src/index.ts
import { Command } from 'commander';
import robot from '@jitsi/robotjs';

interface Config {
  intervalMs: number;
  movementPx: number;
  idleThresholdMs: number;
  mode: 'mouse' | 'keyboard' | 'both';
  verbose: boolean;
}

class TeamsPresenceKeeper {
  private intervalId: NodeJS.Timeout | null = null;
  private lastPos: { x: number; y: number } | null = null;
  private lastActivityTime: number = Date.now();

  constructor(private config: Config) {}

  start(): void {
    this.log('Starting Teams Presence Keeper...');
    this.log(`Config: interval=${this.config.intervalMs}ms, mode=${this.config.mode}`);

    this.intervalId = setInterval(() => {
      this.tick();
    }, this.getRandomInterval());

    process.on('SIGINT', () => this.shutdown());
    process.on('SIGTERM', () => this.shutdown());
  }

  private tick(): void {
    if (!this.shouldActivate()) {
      this.log('User active, skipping...');
      return;
    }

    switch (this.config.mode) {
      case 'mouse':
        this.jiggleMouse();
        break;
      case 'keyboard':
        this.jiggleKeyboard();
        break;
      case 'both':
        Math.random() > 0.5 ? this.jiggleMouse() : this.jiggleKeyboard();
        break;
    }
  }

  private jiggleMouse(): void {
    try {
      const { x, y } = robot.getMousePos();
      const angle = Math.random() * Math.PI * 2;
      const radius = this.config.movementPx;

      const newX = Math.round(x + Math.cos(angle) * radius);
      const newY = Math.round(y + Math.sin(angle) * radius);

      robot.moveMouse(newX, newY);

      // Return to original position after small delay
      setTimeout(() => {
        robot.moveMouse(x, y);
      }, 30 + Math.random() * 50);

      this.log(`Mouse jiggle: (${x},${y}) → (${newX},${newY}) → (${x},${y})`);
    } catch (err) {
      console.error('[ERROR] Mouse jiggle failed:', err);
      console.error('[ERROR] Make sure Accessibility permission is granted');
    }
  }

  private jiggleKeyboard(): void {
    try {
      // Shift key press/release - produces no visible output
      robot.keyToggle('shift', 'down');
      robot.keyToggle('shift', 'up');
      this.log('Keyboard jiggle: Shift press/release');
    } catch (err) {
      console.error('[ERROR] Keyboard jiggle failed:', err);
    }
  }

  private shouldActivate(): boolean {
    const currentPos = robot.getMousePos();

    if (this.lastPos && 
        (currentPos.x !== this.lastPos.x || currentPos.y !== this.lastPos.y)) {
      // User moved mouse - reset activity timer
      this.lastActivityTime = Date.now();
    }

    this.lastPos = currentPos;

    const idleTime = Date.now() - this.lastActivityTime;
    return idleTime > this.config.idleThresholdMs;
  }

  private getRandomInterval(): number {
    // Add ±30% variance to avoid detection patterns
    const base = this.config.intervalMs;
    const variance = base * 0.3;
    return Math.round(base + (Math.random() * 2 - 1) * variance);
  }

  private log(message: string): void {
    if (this.config.verbose) {
      const timestamp = new Date().toISOString();
      console.log(`[${timestamp}] ${message}`);
    }
  }

  private shutdown(): void {
    this.log('Shutting down...');
    if (this.intervalId) {
      clearInterval(this.intervalId);
    }
    process.exit(0);
  }
}

// CLI
const program = new Command();

program
  .name('teams-presence')
  .description('Keep MS Teams status always Available by simulating activity')
  .version('1.0.0')
  .option('-i, --interval <ms>', 'Interval between activities (ms)', '60000')
  .option('-p, --pixels <px>', 'Mouse movement distance (pixels)', '2')
  .option('-t, --threshold <ms>', 'Idle threshold before activating (ms)', '30000')
  .option('-m, --mode <mode>', 'Activity mode: mouse, keyboard, both', 'mouse')
  .option('-v, --verbose', 'Enable verbose logging', false)
  .action((options) => {
    const config: Config = {
      intervalMs: parseInt(options.interval, 10),
      movementPx: parseInt(options.pixels, 10),
      idleThresholdMs: parseInt(options.threshold, 10),
      mode: options.mode as 'mouse' | 'keyboard' | 'both',
      verbose: options.verbose,
    };

    console.log('');
    console.log('╔════════════════════════════════════════╗');
    console.log('║     Teams Presence Keeper v1.0.0       ║');
    console.log('╚════════════════════════════════════════╝');
    console.log('');
    console.log('Press Ctrl+C to stop');
    console.log('');

    const keeper = new TeamsPresenceKeeper(config);
    keeper.start();
  });

program.parse();
